const canon = (s) => { const n = norm(s); return ALIAS[n] || n; };
const pairKey = (a, b) => [canon(a), canon(b)].sort().join("|");
const txt = (v) => (v == null ? "" : typeof v === "string" ? v : String(v));
const isNum = (v) => typeof v === "number" && !isNaN(v);
const intOf = (v) => { if (isNum(v)) return Math.round(v); const m = txt(v).match(/-?\d+/); return m ? parseInt(m[0], 10) : null; };
