/* ---------- import-parser (kun engangs/bootstrap) ---------- */
const KW = { home: ["hjemmelag", "hjemme", "home"], away: ["bortelag", "borte", "away", "gjest"], date: ["dato", "date", "dag"], group: ["gruppe", "group", "runde", "round", "fase", "kamp"] };
const HEADERWORDS = ["hjemmelag", "bortelag", "hjemme", "borte", "resultat", "result", "dato", "date", "gruppe", "group", "runde", "kamp", "tips", "tippet", "tipp", "poeng", "points", "sum", "total", "deltaker", "navn", "fasit", "mal", "score", "spiller"];
