function hydrate(d, source) { const results = d.results || {}; const all = computeAll(results, d.fixtures, d.participants); return { fixtures: d.fixtures, participants: d.participants, results, poengtavle: d.poengtavle || {}, source, lastUpdated: d.lastUpdated || Date.now(), prevRanking: d.prevRanking || all.rows.map((r) => r.p.id), history: d.history || [{ t: Date.now(), pts: Object.fromEntries(all.rows.map((r) => [r.p.id, r.pts])) }], lastSource: d.lastSource || null, log: d.log || [] }; }

