/* ---------- poengmotor ---------- */
function catOf(pr, res) { if (!pr || !res) return "none"; if (pr[0] === res[0] && pr[1] === res[1]) return "exact"; if (Math.sign(pr[0] - pr[1]) === Math.sign(res[0] - res[1])) return "outcome"; return "miss"; }
const ptsOf = (cat) => (cat === "exact" ? GROUP_OUTCOME + GROUP_EXACT_BONUS : cat === "outcome" ? GROUP_OUTCOME : 0);
function computeAll(results, fixtures, participants) {
  const played = fixtures.filter((f) => results[f.id]); const remaining = fixtures.filter((f) => !results[f.id]);
  const rows = participants.map((p) => {
    let pts = 0, exact = 0, hits = 0, miss = 0, goals = 0, bold = 0, predicted = 0; const per = {};
    fixtures.forEach((f) => {
      const pr = p.preds[f.id]; if (pr) { predicted++; goals += pr[0] + pr[1]; if (Math.abs(pr[0] - pr[1]) >= 2) bold++; }
      const res = results[f.id]; const cat = catOf(pr, res); per[f.id] = cat;
      if (res && pr) { pts += ptsOf(cat); if (cat === "exact") { exact++; hits++; } else if (cat === "outcome") hits++; else miss++; }
    });
    const ko = p.sluttspill || 0, bonus = p.bonus || 0, adjust = p.adjust || 0, total = pts + ko + bonus + adjust;
    const playedPred = played.filter((f) => p.preds[f.id]).sort((a, b) => (a.date || "").localeCompare(b.date || "") || a.idx - b.idx).slice(-6);
    const form = playedPred.map((f) => per[f.id]); const settled = hits + miss; const hitRate = settled ? Math.round((100 * hits) / settled) : 0;
    const maxRemaining = remaining.filter((f) => p.preds[f.id]).length * MAXPER;
    return { p, pts, group: pts, ko, bonus, adjust, total, exact, hits, miss, goals, bold, predicted, per, form, hitRate, settled, theoryMax: total + maxRemaining + (KO_MAX - ko) + (BONUS_MAX - bonus) };
  });
  rows.sort((a, b) => b.total - a.total || b.pts - a.pts || b.exact - a.exact || a.p.name.localeCompare(b.p.name, "no"));
  rows.forEach((r, i) => (r.rank = i + 1));
  return { rows, played, remaining, totalRemaining: remaining.length * MAXPER + KO_MAX + BONUS_MAX };
}

/* ---------- lagring ---------- */
// Lokal lagring for bilder o.l. (kjører på Netlify – ikke et Claude-artifact, så localStorage er ok).
// De 18 deltakerbildene ligger uansett innbakt i SEED.photos og er delt for alle.
async function sget(key) { try { return localStorage.getItem(key); } catch { return null; } }
async function sset(key, val) { try { localStorage.setItem(key, typeof val === "string" ? val : JSON.stringify(val)); return true; } catch { return false; } }

// Delt tilstand (resultater) via Netlify-backend. Alle ser samme tabell.
async function apiGetState() { try { const r = await fetch("/api/state", { cache: "no-store" }); if (!r.ok) return null; return await r.json(); } catch { return null; } }
async function apiSaveState(state) { try { const r = await fetch("/api/state", { method: "POST", headers: { "Content-Type": "application/json" }, body: JSON.stringify({ results: state.results, lastUpdated: state.lastUpdated, lastSource: state.lastSource }) }); return r.ok; } catch { return false; } }
async function apiRefresh() { const r = await fetch("/api/refresh", { method: "POST" }); if (!r.ok) throw new Error("refresh " + r.status); return await r.json(); }

/* ---------- format ---------- */
const fmtDate = (iso) => iso ? new Date(iso + "T12:00:00").toLocaleDateString("no-NO", { day: "2-digit", month: "short" }) : "—";
const fmtStamp = (ts) => ts ? new Date(ts).toLocaleString("no-NO", { day: "2-digit", month: "short", hour: "2-digit", minute: "2-digit" }) : "—";
const koDate = (f) => f.date ? new Date(f.date + "T20:00:00") : null;
function countdown(t) { if (!t) return null; const ms = t.getTime() - Date.now(); if (ms <= 0) return null; const d = Math.floor(ms / 86400000), h = Math.floor((ms % 86400000) / 3600000), m = Math.floor((ms % 3600000) / 60000); return d > 0 ? `${d}d ${h}t` : h > 0 ? `${h}t ${m}m` : `${m}m`; }
const AVA = ["#16a34a", "#0ea5e9", "#f59e0b", "#ef4444", "#8b5cf6", "#ec4899", "#14b8a6", "#FC9E78", "#22d3ee", "#65a30d"];
const avaColor = (id) => AVA[(id.charCodeAt(id.length - 1) + id.length) % AVA.length];
const initials = (name) => name.split(/\s+/).filter(Boolean).map((w) => w[0]).join("").slice(0, 2).toUpperCase();
const AXIS = "#94a3b8";

/* ============================================================================ SMÅKOMPONENTER ============================================================================ */
function Avatar({ id, name, photo, size = 40, ring }) { if (photo) return <img src={photo} alt={name} style={{ width: size, height: size, borderRadius: 12 }} className={`object-cover ${ring ? "ring-2 ring-amber-400" : ""}`} />; return <div style={{ width: size, height: size, background: avaColor(id), borderRadius: 12, fontSize: size * 0.36 }} className={`flex items-center justify-center font-extrabold text-white shrink-0 ${ring ? "ring-2 ring-amber-400" : ""}`}>{initials(name)}</div>; }
function Delta({ d }) { if (d == null) return <Minus size={14} className="muted" />; if (d > 0) return <span className="inline-flex items-center text-emerald-500 font-bold text-xs"><TrendingUp size={14} className="mr-0.5" />{d}</span>; if (d < 0) return <span className="inline-flex items-center text-rose-400 font-bold text-xs"><TrendingDown size={14} className="mr-0.5" />{-d}</span>; return <Minus size={14} className="muted" />; }
function FormDots({ form }) { const col = (c) => c === "exact" ? "bg-emerald-500" : c === "outcome" ? "bg-amber-400" : c === "miss" ? "bg-rose-400" : "bg-gray-400"; return <div className="flex gap-1">{form.length === 0 ? <span className="muted text-xs">ingen kamper enda</span> : form.map((c, i) => <span key={i} className={`w-2.5 h-2.5 rounded-full ${col(c)}`} />)}</div>; }
function useCount(target) { const [v, setV] = useState(target); const prev = useRef(target); useEffect(() => { const from = prev.current, to = target; prev.current = target; if (from === to) { setV(to); return; } const dur = 700, t0 = performance.now(); let raf; const step = (t) => { const k = Math.min(1, (t - t0) / dur); setV(Math.round(from + (to - from) * (1 - Math.pow(1 - k, 3)))); if (k < 1) raf = requestAnimationFrame(step); }; raf = requestAnimationFrame(step); return () => cancelAnimationFrame(raf); }, [target]); return v; }
function Pts({ v }) { const n = useCount(v); return <>{n}</>; }
function Confetti({ on }) { if (!on) return null; const cols = ["#16a34a", "#f59e0b", "#ef4444", "#3b82f6", "#FC9E78", "#fde047", "#22c55e"]; return <div className="pointer-events-none fixed inset-0 z-[70] overflow-hidden">{Array.from({ length: 90 }).map((_, i) => { const w = 6 + Math.random() * 8; return <span key={i} className="confetti" style={{ left: Math.random() * 100 + "%", background: cols[i % cols.length], animationDelay: Math.random() * 0.6 + "s", animationDuration: 2.4 + Math.random() * 1.8 + "s", width: w + "px", height: w * 1.6 + "px" }} />; })}</div>; }


